import React, { useState, useEffect } from "react";

function About() {
const images = [
"src\assets\ab-hl-1.webp",
"/images/slide2.jpg",
"/images/slide3.jpg",
"/images/slide4.jpg",
"/images/slide5.jpg"
];

const [currentIndex, setCurrentIndex] = useState(0);

useEffect(() => {
const interval = setInterval(() => {
setCurrentIndex((prevIndex) =>
prevIndex === images.length - 1 ? 0 : prevIndex + 1
);
}, 4000); // change every 4s
return () => clearInterval(interval);
}, [images.length]);

const aboutStyle = {
position: "relative",
height: "400px",
backgroundImage: `url(${images[currentIndex]})`,
backgroundSize: "cover",
backgroundPosition: "center",
display: "flex",
justifyContent: "center",
alignItems: "center",
transition: "background-image 1s ease-in-out",
color: "#fff",
textAlign: "center"
};

const overlayStyle = {
background: "rgba(0, 0, 0, 0.5)",
padding: "30px",
borderRadius: "10px",
maxWidth: "600px"
};

return ( <section id="about-section" style={aboutStyle}> <div style={overlayStyle}> <h2>About Us</h2> <p>
HEALink connects people to reliable healthcare services — book
pathology, find blood banks, and access teleconsultations quickly. Our
mission is to make healthcare accessible and simple. </p> </div> </section>
);
}

export default About;
